
.block-progress {
  display: flex;
  gap: 2px;
  height: 6px;

  .segment {
    flex: 1;
    background: rgba(255, 255, 255, 0.05);
    border-radius: 1px;
    transition: all 0.3s ease;

    &.active {
      background: linear-gradient(180deg, #a855f7, #06b6d4);
    }

    &.glow {
      box-shadow: 0 0 8px currentColor;
      filter: brightness(1.5);
    }
  }
}
