
.character-detail {
  display: flex;
  flex-direction: column;
  gap: 32px;
  padding-bottom: 80px;
}

.edit-mode-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
  padding: 8px 0;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);

  .btn-complete {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 8px 16px;
    border-radius: 8px;
    border: none;
    cursor: pointer;
    font-size: 14px;
    font-weight: 500;
    background: #22c55e;
    color: #fff;

    &:hover { background: #16a34a; }
  }

  .btn-cancel {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 8px 16px;
    border-radius: 8px;
    border: none;
    cursor: pointer;
    font-size: 14px;
    font-weight: 500;
    background: #ef4444;
    color: #fff;

    &:hover { background: #dc2626; }
  }
}

.back-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 14px;
  color: #a1a1aa;
  background: transparent;
  border: none;
  cursor: pointer;
  transition: color 0.2s;
  width: fit-content;

  &:hover {
    color: #fff;
  }
}

:global(.light) .back-btn:hover {
  color: #18181b;
}

.profile-header {
  display: flex;
  align-items: flex-end;
  gap: 24px;

  .avatar-edit {
    width: 128px;
    height: 128px;
    border-radius: 16px;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow: hidden;
    cursor: pointer;
    border: 1px solid rgba(255, 255, 255, 0.1);
    background: rgba(255, 255, 255, 0.02);

    i {
      font-size: 48px;
      color: #52525b;
      transition: transform 0.5s ease;
    }

    &:hover i {
      transform: scale(1.1);
    }

    .edit-overlay {
      position: absolute;
      inset: 0;
      display: flex;
      align-items: center;
      justify-content: center;
      background: rgba(0, 0, 0, 0.5);
      opacity: 0;
      transition: opacity 0.3s;

      i {
        font-size: 20px;
        color: #fff;
        transform: none;
      }
    }

    &:hover .edit-overlay {
      opacity: 1;
    }
  }

  .profile-info {
    flex: 1;
    padding-bottom: 8px;

    .name-row {
      display: flex;
      align-items: center;
      gap: 12px;
      margin-bottom: 8px;

      h2 {
        font-size: 36px;
        font-weight: 700;
        letter-spacing: -0.02em;
        color: #fff;
      }
    }

    .meta {
      font-size: 14px;
      color: #a1a1aa;
      font-family: monospace;
    }
  }
}

:global(.light) .profile-header {
  .avatar-edit {
    border-color: rgba(0, 0, 0, 0.1);
    background: #f4f4f5;
  }

  .profile-info .name-row h2 {
    color: #18181b;
  }
}

.edit-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s;
  border: none;
  background: rgba(255, 255, 255, 0.05);
  color: #e4e4e7;
  margin-bottom: 8px;

  &:hover {
    background: rgba(255, 255, 255, 0.1);
  }
}

:global(.light) .edit-btn {
  background: rgba(0, 0, 0, 0.05);
  color: #27272a;

  &:hover {
    background: rgba(0, 0, 0, 0.1);
  }
}

.detail-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 24px;

  @media (min-width: 768px) {
    grid-template-columns: repeat(2, 1fr);
  }
}

.detail-card {
  padding: 24px;
  border-radius: 16px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.02);
  display: flex;
  flex-direction: column;
  gap: 24px;

  .card-title {
    display: flex;
    align-items: center;
    gap: 12px;
    padding-bottom: 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);

    i {
      font-size: 20px;
      color: #d4d4d8;
    }

    h3 {
      font-size: 18px;
      font-weight: 500;
      color: #f4f4f5;
      flex: 1;
    }

    .edit-mini-btn {
      font-size: 12px;
      color: #a1a1aa;
      background: transparent;
      border: none;
      cursor: pointer;
      transition: color 0.2s;

      &:hover {
        color: #fff;
      }
    }
  }
}

:global(.light) .detail-card {
  border-color: rgba(0, 0, 0, 0.1);
  background: #fff;

  .card-title {
    border-color: rgba(0, 0, 0, 0.1);

    i { color: #52525b; }
    h3 { color: #18181b; }
  }
}

.stats-list {
  display: flex;
  flex-direction: column;
  gap: 16px;

  &.edit-stats .stat-row.edit {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 12px;

    .label {
      font-size: 14px;
      color: #71717a;
      flex-shrink: 0;
    }

    .edit-value {
      flex: 1;
      max-width: 180px;
      padding: 6px 10px;
      border-radius: 6px;
      font-size: 14px;
      border: 1px solid rgba(255, 255, 255, 0.2);
      background: rgba(255, 255, 255, 0.05);
      color: #fff;
      outline: none;
    }
  }
}

:global(.light) .stats-list.edit-stats .stat-row.edit .edit-value {
  border-color: rgba(0, 0, 0, 0.15);
  background: #fff;
  color: #18181b;
}

.edit-name-input {
  font-size: 36px;
  font-weight: 700;
  padding: 4px 8px;
  border-radius: 8px;
  border: 1px solid rgba(255, 255, 255, 0.2);
  background: rgba(255, 255, 255, 0.05);
  color: #fff;
  outline: none;
  width: 100%;
  max-width: 320px;
}

:global(.light) .edit-name-input {
  border-color: rgba(0, 0, 0, 0.15);
  background: #fff;
  color: #18181b;
}

.stat-bars {
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding-top: 24px;
  border-top: 1px solid rgba(255, 255, 255, 0.05);
}

:global(.light) .stat-bars {
  border-color: rgba(0, 0, 0, 0.05);
}

.physiology-summary {
  margin-top: 20px;
  padding-top: 16px;
  border-top: 1px solid rgba(255, 255, 255, 0.05);

  .section-label {
    display: block;
    font-size: 12px;
    color: #71717a;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin-bottom: 8px;
  }

  .thought-text {
    font-size: 14px;
    color: #d4d4d8;
    line-height: 1.6;
  }
}

:global(.light) .physiology-summary {
  border-color: rgba(0, 0, 0, 0.05);

  .thought-text {
    color: #3f3f46;
  }
}

.psych-content,
.fetish-content {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.thought-section {
  .section-label {
    display: block;
    font-size: 12px;
    color: #71717a;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin-bottom: 8px;
  }

  .thought-text {
    font-size: 14px;
    color: #d4d4d8;
    font-style: italic;
    line-height: 1.6;
  }
}

:global(.light) .thought-section .thought-text {
  color: #3f3f46;
}

.traits-section,
.sensitive-section {
  .section-label {
    display: block;
    font-size: 12px;
    color: #71717a;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin-bottom: 12px;
  }

  .badges {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
  }
}

.empty-hint {
  font-size: 14px;
  color: #71717a;
}

.rules-grid .empty-hint {
  padding: 12px 0;
}

.hidden-fetish {
  .section-label {
    display: block;
    font-size: 12px;
    color: #71717a;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin-bottom: 8px;
  }

  p {
    font-size: 14px;
    color: #d4d4d8;
    line-height: 1.6;
  }
}

:global(.light) .hidden-fetish p {
  color: #3f3f46;
}

.rules-card {
  padding: 24px;
  border-radius: 16px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.02);

  .rules-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding-bottom: 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
    margin-bottom: 24px;

    .title-group {
      display: flex;
      align-items: center;
      gap: 12px;

      i {
        font-size: 20px;
        color: #d4d4d8;
      }

      h3 {
        font-size: 18px;
        font-weight: 500;
        color: #f4f4f5;
      }
    }

    .manage-btn {
      font-size: 12px;
      color: #a1a1aa;
      background: transparent;
      border: none;
      cursor: pointer;
      transition: color 0.2s;

      &:hover {
        color: #fff;
      }
    }
  }
}

:global(.light) .rules-card {
  border-color: rgba(0, 0, 0, 0.1);
  background: #fff;

  .rules-header {
    border-color: rgba(0, 0, 0, 0.1);

    .title-group {
      i { color: #52525b; }
      h3 { color: #18181b; }
    }

    .manage-btn {
      color: #71717a;

      &:hover {
        color: #18181b;
      }
    }
  }
}

.rules-grid {
  display: flex;
  flex-direction: column;
  gap: 0;
}

.personal-rule-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 0;
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);

  &:last-child {
    border-bottom: none;
  }

  .rule-desc {
    font-size: 13px;
    color: #a1a1aa;
    flex: 1;
    margin-right: 12px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .rule-actions {
    display: flex;
    gap: 4px;
    flex-shrink: 0;

    .action {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 28px;
      height: 28px;
      padding: 0;
      border: none;
      border-radius: 4px;
      cursor: pointer;
      transition: all 0.2s;
      font-size: 12px;

      &.edit {
        color: #60a5fa;
        background: rgba(96, 165, 250, 0.1);

        &:hover {
          background: rgba(96, 165, 250, 0.2);
        }
      }

      &.archive {
        color: #f59e0b;
        background: rgba(245, 158, 11, 0.1);

        &:hover {
          background: rgba(245, 158, 11, 0.2);
        }
      }

      &.delete {
        color: #ef4444;
        background: rgba(239, 68, 68, 0.1);

        &:hover {
          background: rgba(239, 68, 68, 0.2);
        }
      }
    }
  }
}

:global(.light) .personal-rule-row {
  border-color: rgba(0, 0, 0, 0.05);

  .rule-desc {
    color: #71717a;
  }
}

// 可点击的徽章样式
.clickable-badge {
  cursor: pointer;
  transition: all 0.2s;

  &:hover {
    transform: scale(1.05);
    box-shadow: 0 0 8px rgba(255, 255, 255, 0.2);
  }
}

// 详情展开面板
.detail-expand-panel {
  margin-top: 12px;
  padding: 16px;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  animation: slideDown 0.2s ease-out;

  .detail-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
    padding-bottom: 8px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);

    .detail-title {
      font-size: 16px;
      font-weight: 600;
      color: #f472b6;
    }

    .close-btn {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 24px;
      height: 24px;
      border: none;
      border-radius: 50%;
      background: rgba(255, 255, 255, 0.1);
      color: #a1a1aa;
      cursor: pointer;
      transition: all 0.2s;

      &:hover {
        background: rgba(239, 68, 68, 0.3);
        color: #ef4444;
      }
    }
  }

  .detail-body {
    display: flex;
    flex-direction: column;
    gap: 12px;

    .detail-row {
      display: flex;
      flex-direction: column;
      gap: 4px;

      .detail-label {
        font-size: 11px;
        color: #71717a;
        text-transform: uppercase;
        letter-spacing: 0.05em;
      }

      .detail-value {
        font-size: 14px;
        color: #d4d4d8;
        line-height: 1.5;
      }
    }
  }
}

@keyframes slideDown {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

// 身份标签样式
.identity-content {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.identity-tag-row {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 8px 12px;
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.05);

  .identity-category {
    flex-shrink: 0;
    min-width: 80px;
    font-size: 12px;
    font-weight: 500;
    color: #a78bfa;
    text-transform: uppercase;
    letter-spacing: 0.05em;
  }

  .identity-value {
    font-size: 14px;
    color: #d4d4d8;
    line-height: 1.5;
  }
}

:global(.light) {
  .detail-expand-panel {
    background: rgba(0, 0, 0, 0.03);
    border-color: rgba(0, 0, 0, 0.1);

    .detail-header {
      border-color: rgba(0, 0, 0, 0.1);

      .detail-title {
        color: #db2777;
      }

      .close-btn:hover {
        background: rgba(239, 68, 68, 0.15);
        color: #dc2626;
      }
    }

    .detail-body .detail-row {
      .detail-label {
        color: #71717a;
      }
      .detail-value {
        color: #3f3f46;
      }
    }
  }

  .identity-tag-row {
    background: rgba(0, 0, 0, 0.02);
    border-color: rgba(0, 0, 0, 0.08);

    .identity-category {
      color: #7c3aed;
    }

    .identity-value {
      color: #3f3f46;
    }
  }

  .clickable-badge:hover {
    box-shadow: 0 0 8px rgba(0, 0, 0, 0.15);
  }
}
