// 标签验证弹窗样式 - 紧凑设计
.tag-validation-overlay {
  z-index: 10001;
  align-items: flex-start;
  justify-content: center;
  padding: 8px 10px;
  padding-top: calc(48px * var(--ui-scale, 1));
}

.tag-validation-modal {
  max-width: 440px;
  width: 100%;
  max-height: min(78vh, calc(100dvh - 88px));
  overflow-y: auto;
}

.tag-validation-modal .modal-header {
  padding: 10px 14px;

  h2 {
    font-size: 15px;
  }
}

.tag-validation-modal .modal-body {
  padding: 10px 14px;
  min-height: auto;
}

.tag-validation-modal .modal-footer {
  padding: 10px 14px;
}

.tag-validation-content {
  .validation-intro {
    font-size: 12px;
    color: #a1a1aa;
    margin: 0 0 4px;
    line-height: 1.35;
  }

  .ai-output-time {
    font-size: 11px;
    margin-bottom: 8px;
    font-family: ui-monospace, monospace;
    opacity: 0.95;
    color: #a1a1aa;
  }

  .tag-status-list {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 6px;

    @media (max-width: 380px) {
      grid-template-columns: 1fr;
    }
  }

  .tag-status-item {
    padding: 6px 8px;
    border-radius: 6px;
    border: 1px solid rgba(255, 255, 255, 0.1);
    background: rgba(255, 255, 255, 0.02);
    min-width: 0;

    &.is-valid {
      border-color: rgba(34, 197, 94, 0.3);
      background: rgba(34, 197, 94, 0.05);
    }

    &.is-invalid {
      border-color: rgba(239, 68, 68, 0.3);
      background: rgba(239, 68, 68, 0.05);
    }

    &.is-warning {
      border-color: rgba(234, 179, 8, 0.45);
      background: rgba(234, 179, 8, 0.08);
    }
  }

  .tag-status-header {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 6px;
    margin-bottom: 2px;
  }

  .tag-name {
    font-size: 12px;
    font-weight: 600;
    color: #e4e4e7;
    line-height: 1.25;
    min-width: 0;
  }

  .tag-name-code {
    display: block;
    font-family: ui-monospace, monospace;
    font-size: 10px;
    font-weight: 500;
    opacity: 0.75;
    margin-top: 2px;
    word-break: break-all;
  }

  .tag-badge {
    flex-shrink: 0;
    font-size: 10px;
    padding: 2px 5px;
    border-radius: 4px;
    font-weight: 500;

    &.badge-success {
      background: rgba(34, 197, 94, 0.15);
      color: #22c55e;
    }

    &.badge-error {
      background: rgba(239, 68, 68, 0.15);
      color: #ef4444;
    }

    &.badge-warning {
      background: rgba(234, 179, 8, 0.18);
      color: #eab308;
    }
  }

  .tag-message {
    font-size: 11px;
    color: #71717a;
    margin: 0;
    line-height: 1.35;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  .validation-duplicate-hint {
    margin-bottom: 8px;
    padding: 8px 10px;
    border-radius: 6px;
    background: rgba(234, 179, 8, 0.12);
    border: 1px solid rgba(234, 179, 8, 0.35);
    display: flex;
    align-items: flex-start;
    gap: 6px;
    font-size: 11px;
    color: #eab308;
    line-height: 1.4;

    i {
      font-size: 11px;
      margin-top: 2px;
      flex-shrink: 0;
    }
  }

  .validation-warning {
    margin-top: 8px;
    padding: 8px 10px;
    border-radius: 6px;
    background: rgba(245, 158, 11, 0.1);
    border: 1px solid rgba(245, 158, 11, 0.2);
    display: flex;
    align-items: flex-start;
    gap: 6px;
    font-size: 11px;
    color: #f59e0b;

    i {
      font-size: 11px;
      margin-top: 1px;
    }
  }

  .ai-output-section {
    margin-top: 8px;
  }

  .ai-output-toggle {
    font-size: 12px;
    padding: 6px 0;
  }
}

.dark .tag-validation-content {
  .validation-intro { color: #a1a1aa; }
  .ai-output-time { color: #a1a1aa; }
  .tag-name { color: #e4e4e7; }
  .tag-message { color: #71717a; }
}

.light .tag-validation-content {
  .validation-intro { color: #71717a; }
  .ai-output-time { color: #71717a; }
  .tag-name { color: #27272a; }
  .tag-message { color: #a1a1aa; }

  .tag-status-item {
    border-color: rgba(0, 0, 0, 0.1);
    background: #fff;

    &.is-valid {
      border-color: rgba(34, 197, 94, 0.3);
      background: rgba(34, 197, 94, 0.05);
    }

    &.is-invalid {
      border-color: rgba(239, 68, 68, 0.3);
      background: rgba(239, 68, 68, 0.05);
    }

    &.is-warning {
      border-color: rgba(234, 179, 8, 0.45);
      background: rgba(254, 251, 231, 0.95);
    }
  }
}

.tag-validation-footer {
  display: flex;
  justify-content: flex-end;
  gap: 10px;

  button {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 8px 16px; // 减小按钮 padding
    font-size: 13px; // 减小字体
  }
}

.btn-rollback {
