
@use '../styles/cyber-effects' as *;

// ===== 赛博朋克风格封面页 =====
// 与主界面 #app-root.rule-modifier 一致：由 App 注入 --ui-scale、--ui-max-width、--ui-max-height（localStorage uiLayout）
.opening-form {
  font-size: calc(14px * var(--ui-scale, 1));
  line-height: 1.5;
  --space-xs: calc(4px * var(--ui-scale, 1));
  --space-sm: calc(8px * var(--ui-scale, 1));
  --space-md: calc(12px * var(--ui-scale, 1));
  --space-lg: calc(16px * var(--ui-scale, 1));
  --space-xl: calc(24px * var(--ui-scale, 1));
  --radius-sm: calc(6px * var(--ui-scale, 1));
  --radius-md: calc(8px * var(--ui-scale, 1));
  --radius-lg: calc(12px * var(--ui-scale, 1));
  --radius-xl: calc(16px * var(--ui-scale, 1));

  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: calc(32px * var(--ui-scale, 1));
  position: relative;
  overflow: hidden;

  &.dark {
    background: #050508;
  }
}

// 书本容器
.book-container {
  width: 100%;
  max-width: min(1400px, var(--ui-max-width, 100%));
  height: 85vh;
  max-height: min(85vh, calc(900px * var(--ui-scale, 1)));
  position: relative;
  border-radius: calc(28px * var(--ui-scale, 1));
  overflow: hidden;
  margin: 0 auto;
}

// HUD 装饰
.hud-decoration {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 5;

  // 四角标记
  .corner-mark {
    position: absolute;
    font-family: 'Courier New', monospace;
    font-size: 10px;
    color: rgba(168, 85, 247, 0.5);

    &.top-left {
      top: 24px;
      left: 24px;

      &::before {
        content: '';
        position: absolute;
        top: -8px;
        left: -8px;
        width: 32px;
        height: 32px;
        border-top: 2px solid rgba(168, 85, 247, 0.4);
        border-left: 2px solid rgba(168, 85, 247, 0.4);
        border-top-left-radius: 8px;
      }
    }

    &.top-right {
      top: 24px;
      right: 24px;
      color: rgba(6, 182, 212, 0.5);

      &::before {
        content: '';
        position: absolute;
        top: -8px;
        right: -8px;
        width: 32px;
        height: 32px;
        border-top: 2px solid rgba(6, 182, 212, 0.4);
        border-right: 2px solid rgba(6, 182, 212, 0.4);
        border-top-right-radius: 8px;
      }
    }

    &.bottom-left {
      bottom: 24px;
      left: 24px;

      &::before {
        content: '';
        position: absolute;
        bottom: -8px;
        left: -8px;
        width: 32px;
        height: 32px;
        border-bottom: 2px solid rgba(168, 85, 247, 0.4);
        border-left: 2px solid rgba(168, 85, 247, 0.4);
        border-bottom-left-radius: 8px;
      }
    }

    &.bottom-right {
      bottom: 24px;
      right: 24px;
      color: rgba(6, 182, 212, 0.5);

      &::before {
        content: '';
        position: absolute;
        bottom: -8px;
        right: -8px;
        width: 32px;
        height: 32px;
        border-bottom: 2px solid rgba(6, 182, 212, 0.4);
        border-right: 2px solid rgba(6, 182, 212, 0.4);
        border-bottom-right-radius: 8px;
      }
    }
  }

  // 顶部 HUD
  .hud-top {
    position: absolute;
    top: 16px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    align-items: center;
    gap: 16px;
    opacity: 0.6;

    .hud-line {
      height: 1px;
      width: 120px;
      background: linear-gradient(90deg, transparent, rgba(168, 85, 247, 0.5));

      &.right {
        background: linear-gradient(90deg, rgba(6, 182, 212, 0.5), transparent);
      }
    }

    .hud-label {
      font-family: 'Courier New', monospace;
      font-size: 10px;
      letter-spacing: 0.3em;
      display: flex;
      gap: 4px;
      color: rgba(255, 255, 255, 0.5);

      .purple { color: rgba(168, 85, 247, 0.8); }
      .cyan { color: rgba(6, 182, 212, 0.8); }
      .dim { color: rgba(255, 255, 255, 0.3); }
    }
  }

  // 底部 HUD
  .hud-bottom {
    position: absolute;
    bottom: 16px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    align-items: center;
    gap: 32px;
    opacity: 0.6;

    .data-blocks {
      display: flex;
      gap: 4px;

      .data-block {
        width: 8px;
        height: 4px;
        background: rgba(168, 85, 247, 0.4);

        &.right .data-block {
          background: rgba(6, 182, 212, 0.4);
        }
      }
    }

    .hud-range {
      font-family: 'Courier New', monospace;
      font-size: 10px;
      color: rgba(255, 255, 255, 0.5);
      letter-spacing: 0.1em;

      .dim { color: rgba(6, 182, 212, 0.5); }
    }
  }

  // 侧边 HUD
  .hud-side {
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 16px;
    opacity: 0.6;

    &.left { left: 24px; }
    &.right { right: 24px; }

    .side-line {
      width: 1px;
      height: 120px;
      background: linear-gradient(to bottom, transparent, rgba(168, 85, 247, 0.5), rgba(168, 85, 247, 0.8));

      &.cyan {
        background: linear-gradient(to bottom, transparent, rgba(6, 182, 212, 0.5), rgba(6, 182, 212, 0.8));
      }
    }

    .side-dots {
      display: flex;
      flex-direction: column;
      gap: 8px;

      .side-dot {
        width: 6px;
        height: 6px;
        border-radius: 50%;
        background: rgba(168, 85, 247, 0.6);
        box-shadow: 0 0 8px rgba(168, 85, 247, 0.8);
        animation: pulse-dot 2s ease-in-out infinite;

        @for $i from 1 through 3 {
          &:nth-child(#{$i}) {
            animation-delay: #{$i * 0.3}s;
          }
        }

        &.cyan {
          background: rgba(6, 182, 212, 0.6);
          box-shadow: 0 0 8px rgba(6, 182, 212, 0.8);
        }
      }
    }

    .side-text {
      font-family: 'Courier New', monospace;
      font-size: 10px;
      letter-spacing: 0.4em;
      writing-mode: vertical-rl;
      text-orientation: mixed;
      padding: 16px 0;

      &.purple {
        color: rgba(168, 85, 247, 0.6);
        transform: rotate(180deg);
      }

      &.cyan {
        color: rgba(6, 182, 212, 0.6);
      }
    }
  }

  // 数据条
  .data-bars {
    position: absolute;
    bottom: 64px;
    display: flex;
    gap: 4px;
    opacity: 0.3;

    &.left { left: 48px; }
    &.right { right: 48px; }

    .data-bar {
      width: 4px;
      background: rgba(168, 85, 247, 0.6);
      border-radius: 2px 2px 0 0;
      animation: data-bar-pulse 2s ease-in-out infinite;

      &.cyan { background: rgba(6, 182, 212, 0.6); }

      @for $i from 1 through 15 {
        &:nth-child(#{$i}) {
          animation-delay: #{$i * 0.1}s;
        }
      }
    }
  }

  // 刻度尺
  .ruler {
    position: absolute;
    top: 25%;
    bottom: 25%;
    width: 8px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    opacity: 0.2;

    &.left { left: 16px; }
    &.right { right: 16px; align-items: flex-end; }

    .ruler-mark {
      height: 1px;
      background: rgba(255, 255, 255, 0.5);
      width: 50%;

      &.long { width: 100%; }
    }
  }
}

@keyframes pulse-dot {
  0%, 100% { opacity: 0.3; }
  50% { opacity: 1; }
}

@keyframes data-bar-pulse {
  0%, 100% { height: 10px; }
  50% { height: 40px; }
}

// 封面页布局 - 三列等宽对称布局
.cover-page {
  display: grid;
  grid-template-columns: 1fr 420px 1fr;
  grid-template-rows: 1fr auto;
  gap: 40px;
  padding: 48px 40px 40px;
  height: 100%;
  position: relative;
  z-index: 10;
  align-items: center;
  min-width: 0;
  width: 100%;
  box-sizing: border-box;
}

// 系统状态面板（左侧）
.system-status-panel {
  display: flex;
  flex-direction: column;
  gap: 24px;
  opacity: 0.8;
  max-width: 320px;
  justify-self: end;

  .panel-section {
    .section-header {
      display: flex;
      align-items: center;
      gap: 8px;
      padding-bottom: 12px;
      margin-bottom: 16px;
      border-bottom: 1px solid rgba(168, 85, 247, 0.3);
      font-family: 'Courier New', monospace;
      font-size: 11px;
      letter-spacing: 0.2em;
      text-transform: uppercase;
      color: rgba(168, 85, 247, 0.8);

      i { font-size: 12px; }
    }

    .status-list {
      display: flex;
      flex-direction: column;
      gap: 16px;

      .status-item {
        .status-label-row {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 6px;
          font-size: 11px;
          font-family: 'Courier New', monospace;
          text-transform: uppercase;
          letter-spacing: 0.1em;

          .status-value {
            color: rgba(255, 255, 255, 0.8);
            font-weight: 500;
          }
        }
      }
    }

    .module-tags {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;

      .module-tag {
        font-family: 'Courier New', monospace;
        font-size: 10px;
        padding: 4px 8px;
        background: rgba(168, 85, 247, 0.1);
        border: 1px solid rgba(168, 85, 247, 0.2);
        border-radius: 4px;
        color: rgba(168, 85, 247, 0.8);
      }
    }
  }
}

// 中央卡片区域
.center-card-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  position: relative;
  width: 100%;
  max-width: 100%;
  min-width: 0;
  box-sizing: border-box;
  padding: 0 6px;

  .glow-border {
    position: absolute;
    inset: -4px;
    background: linear-gradient(90deg, rgba(168, 85, 247, 0.3), rgba(6, 182, 212, 0.3));
    border-radius: 28px;
    filter: blur(12px);
    opacity: 0.5;
    transition: opacity 0.3s;

    &:hover { opacity: 0.8; }
  }

  .center-card {
    position: relative;
    // 必须可随窄屏收缩；勿用固定 380px（会覆盖媒体查询里单独的 .center-card）
    width: min(100%, 380px);
    max-width: 100%;
    min-height: 320px;
    height: auto;
    box-sizing: border-box;
    border-radius: 24px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    overflow: hidden;

    .card-inner-border {
      position: absolute;
      inset: 16px;
      border: 1px solid rgba(255, 255, 255, 0.05);
      border-radius: 16px;
      pointer-events: none;

      &::before {
        content: '';
        position: absolute;
        inset: 16px;
        border: 1px solid rgba(255, 255, 255, 0.05);
        border-radius: 12px;
      }
    }

    .card-content {
      text-align: center;
      z-index: 1;
      width: 100%;
      max-width: 100%;
      min-width: 0;
      padding: 0 4px;
      box-sizing: border-box;
      word-break: break-word;
      overflow-wrap: anywhere;

      .book-icon-wrapper {
        position: relative;
        margin-bottom: 32px;

        .icon-glow {
          position: absolute;
          inset: -20px;
          background: rgba(6, 182, 212, 0.2);
          border-radius: 50%;
          filter: blur(20px);
        }

        .book-icon {
          position: relative;
          font-size: 64px;
          color: rgba(255, 255, 255, 0.9);
          text-shadow: 0 0 20px rgba(255, 255, 255, 0.5);
        }
      }

      .book-title {
        font-size: 40px;
        font-weight: 700;
        margin: 0 0 8px;
        letter-spacing: 0.05em;
      }

      .book-subtitle {
        font-size: 12px;
        letter-spacing: 0.3em;
        text-transform: uppercase;
        margin: 0 0 32px;
        font-weight: 600;
      }

      .book-desc {
        font-size: 14px;
        letter-spacing: 0.1em;
        margin: 0;
        opacity: 0.7;
      }
    }
  }

  // 开始按钮
  .start-btn-wrapper {
    position: relative;
    margin-top: 40px;
    width: 100%;
    max-width: 100%;
    display: flex;
    justify-content: center;
    box-sizing: border-box;
    padding: 0 4px;

    .btn-pulse-ring {
      position: absolute;
      inset: -8px;
      border-radius: 50px;
      background: linear-gradient(90deg, rgba(168, 85, 247, 0.4), rgba(6, 182, 212, 0.4));
      filter: blur(8px);
      opacity: 0.5;
      animation: pulse-ring 3s ease-out infinite;
    }

    .start-btn {
      position: relative;
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 12px;
      max-width: min(100%, 320px);
      padding: 16px 40px;
      border-radius: 50px;
      font-size: 16px;
      font-weight: 500;
      cursor: pointer;
      border: 1px solid rgba(168, 85, 247, 0.3);
      background: rgba(0, 0, 0, 0.4);
      transition: all 0.3s;
      box-sizing: border-box;

      &:hover {
        border-color: rgba(168, 85, 247, 0.6);
        box-shadow: 0 0 30px rgba(168, 85, 247, 0.3);
      }

      i {
        transition: transform 0.3s;
      }

      &:hover i {
        transform: translateX(4px);
      }
    }
  }
}

@keyframes pulse-ring {
  0% { transform: scale(1); opacity: 0.5; }
  100% { transform: scale(1.3); opacity: 0; }
}

// 事件日志面板（右侧）
.event-logs-panel {
  display: flex;
  flex-direction: column;
  gap: 24px;
  opacity: 0.8;
  max-width: 320px;
  justify-self: start;

  .panel-section {
    .section-header {
      display: flex;
      align-items: center;
      gap: 8px;
      padding-bottom: 12px;
      margin-bottom: 16px;
      border-bottom: 1px solid rgba(6, 182, 212, 0.3);
      font-family: 'Courier New', monospace;
      font-size: 11px;
      letter-spacing: 0.2em;
      text-transform: uppercase;
      color: rgba(6, 182, 212, 0.8);

      i { font-size: 12px; }
    }

    .logs-list {
      display: flex;
      flex-direction: column;
      gap: 12px;

      .log-item {
        display: flex;
        gap: 12px;
        font-family: 'Courier New', monospace;
        font-size: 11px;

        .log-time {
          color: rgba(255, 255, 255, 0.4);
        }

        .log-msg {
          color: rgba(255, 255, 255, 0.6);

          &.highlight {
            color: rgba(6, 182, 212, 0.9);
            text-shadow: 0 0 10px rgba(6, 182, 212, 0.5);
          }
        }
      }
    }

    .stats-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 16px;

      .stat-card {
        background: rgba(0, 0, 0, 0.2);
        border: 1px solid rgba(255, 255, 255, 0.05);
        border-radius: 8px;
        padding: 16px;
        text-align: center;

        .stat-value {
          font-size: 28px;
          font-family: 'Courier New', monospace;
          font-weight: bold;
          margin-bottom: 4px;

          &.cyan { color: rgba(6, 182, 212, 0.9); }
          &.purple { color: rgba(168, 85, 247, 0.9); }
        }

        .stat-label {
          font-size: 10px;
          text-transform: uppercase;
          letter-spacing: 0.1em;
          opacity: 0.6;
        }
      }
    }
  }
}

// 底部工具栏
.bottom-tools {
  grid-column: 1 / -1;
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  align-items: center;
  align-content: center;
  gap: 12px 10px;
  margin-top: auto;
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
  padding: 0 6px 4px;
  position: relative;
  z-index: 12;

  .tool-btn {
    display: inline-flex;
    align-items: center;
    gap: 10px;
    padding: 12px 24px;
    border-radius: 12px;
    font-size: 13px;
    cursor: pointer;
    border: 1px solid rgba(255, 255, 255, 0.1);
    background: rgba(255, 255, 255, 0.03);
    transition: all 0.3s;
    color: rgba(255, 255, 255, 0.7);
    flex: 0 1 auto;
    min-width: 0;
    max-width: 100%;
    justify-content: center;
    box-sizing: border-box;

    &:hover {
      background: rgba(255, 255, 255, 0.08);
      border-color: rgba(255, 255, 255, 0.2);
      color: rgba(255, 255, 255, 0.9);
    }

    i {
      font-size: 14px;
      opacity: 0.8;
    }
  }
}

// 原有样式（保留其他页面）
.opening-form {
  --bg-0: #0b0c0f;
  --bg-1: #151820;
  --glass: rgba(255, 255, 255, 0.06);
  --glass-strong: rgba(255, 255, 255, 0.1);
  --line: rgba(255, 255, 255, 0.14);
  --text: rgba(255, 255, 255, 0.92);
  --text-soft: rgba(255, 255, 255, 0.68);
  --text-faint: rgba(255, 255, 255, 0.48);
  --accent: #c7ccd4;
  --danger: #ff6b6b;
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: calc(32px * var(--ui-scale, 1));
  font-size: calc(14px * var(--ui-scale, 1));
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'PingFang SC', 'Noto Sans SC', sans-serif;
  color: var(--text);
  background:
    radial-gradient(1200px 700px at 8% -10%, rgba(255, 255, 255, 0.12), transparent 60%),
    radial-gradient(900px 500px at 108% 110%, rgba(255, 255, 255, 0.08), transparent 60%),
    linear-gradient(160deg, var(--bg-0) 0%, var(--bg-1) 100%);

  &.light {
    --bg-0: #eef1f6;
    --bg-1: #dee3ea;
    --glass: rgba(255, 255, 255, 0.62);
    --glass-strong: rgba(255, 255, 255, 0.82);
    --line: rgba(17, 24, 39, 0.12);
    --text: rgba(17, 24, 39, 0.92);
    --text-soft: rgba(17, 24, 39, 0.68);
    --text-faint: rgba(17, 24, 39, 0.48);
    --accent: #3a4352;
    --danger: #dc3c3c;
  }
}

.book-container {
  width: 100%;
  max-width: min(880px, var(--ui-max-width, 100%));
  min-height: calc(690px * var(--ui-scale, 1));
  position: relative;
  border-radius: calc(28px * var(--ui-scale, 1));
  overflow: hidden;
  background: var(--glass);
  border: 1px solid var(--line);
  box-shadow:
    0 calc(30px * var(--ui-scale, 1)) calc(80px * var(--ui-scale, 1)) rgba(0, 0, 0, 0.32),
    inset 0 1px 0 rgba(255, 255, 255, 0.22);
  backdrop-filter: blur(20px) saturate(140%);

  &::before {
    content: '';
    position: absolute;
    inset: 0;
    pointer-events: none;
    background: linear-gradient(
      180deg,
      rgba(255, 255, 255, 0.12) 0%,
      rgba(255, 255, 255, 0.02) 24%,
      rgba(255, 255, 255, 0.05) 100%
    );
  }

  &.flipping .book-page {
    animation: pageSwitch 0.24s cubic-bezier(0.22, 1, 0.36, 1);
  }
}

@keyframes pageSwitch {
  0% {
    opacity: 0.65;
    transform: translateY(8px) scale(0.99);
  }
  100% {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.book-page {
  position: relative;
  width: 100%;
  min-height: calc(690px * var(--ui-scale, 1));
  overflow-x: hidden;
  overflow-y: auto;
  box-sizing: border-box;
}

// 与上方 .cover-page 合并：勿再写第二段 .cover-page，否则会打乱响应式 padding

.book-cover {
  width: 100%;
  max-width: 460px;
}

.cover-decoration {
  border-radius: 24px;
  padding: 22px;
  border: 1px solid var(--line);
  background: rgba(255, 255, 255, 0.04);
  backdrop-filter: blur(8px);
}

.cover-border {
  border-radius: 18px;
  border: 1px solid var(--line);
  padding: 18px;
}

.cover-inner {
  border-radius: 14px;
  padding: 40px 22px;
  background: rgba(255, 255, 255, 0.03);
}

.book-icon {
  font-size: 58px;
  color: var(--accent);
  margin-bottom: 20px;
}

.book-title {
  margin: 0 0 8px;
  font-size: 40px;
  line-height: 1.1;
  letter-spacing: 0.02em;
  font-weight: 700;
}

.book-subtitle {
  margin: 0 0 20px;
  font-size: 12px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--text-faint);
}

.cover-divider {
  width: 72%;
  height: 1px;
  margin: 0 auto 18px;
  background: linear-gradient(90deg, transparent, var(--line), transparent);
}

.book-desc {
  margin: 0 0 30px;
  font-size: 15px;
  color: var(--text-soft);
}

.start-btn {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 14px 34px;
  border-radius: 14px;
  border: 1px solid var(--line);
  background: linear-gradient(
    180deg,
    rgba(255, 255, 255, 0.22) 0%,
    rgba(255, 255, 255, 0.08) 100%
  );
  color: var(--text);
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.18s ease, box-shadow 0.18s ease, border-color 0.18s ease;

  &:hover {
