}

.library-toolbar-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 16px;
  border-radius: 12px;
  border: 1px solid rgba(168, 85, 247, 0.3);
  background: rgba(168, 85, 247, 0.08);
  color: rgba(168, 85, 247, 0.9);
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
  animation: toolbar-btn-pulse 3s ease-in-out infinite;

  &::before {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, rgba(168, 85, 247, 0.2), rgba(6, 182, 212, 0.2));
    opacity: 0;
    transition: opacity 0.3s;
  }

  &:hover {
    color: #fff;
    border-color: rgba(6, 182, 212, 0.5);
    transform: translateY(-2px);
    box-shadow:
      0 8px 20px rgba(168, 85, 247, 0.2),
      0 0 15px rgba(6, 182, 212, 0.2);

    &::before {
      opacity: 1;
    }
  }

  i {
    position: relative;
    z-index: 1;
    font-size: 14px;
  }
}

@keyframes toolbar-btn-pulse {
  0%, 100% {
    box-shadow:
      0 0 5px rgba(168, 85, 247, 0.2),
      inset 0 0 10px rgba(168, 85, 247, 0.05);
  }
  50% {
    box-shadow:
      0 0 15px rgba(168, 85, 247, 0.3),
      0 0 25px rgba(6, 182, 212, 0.2),
      inset 0 0 15px rgba(168, 85, 247, 0.1);
  }
}

.custom-rule-actions {
  display: flex;
  align-items: flex-start;
  gap: 6px;
  flex-shrink: 0;
}

.library-mini-btn {
  width: 30px;
  height: 30px;
  border-radius: 10px;
  border: 1px solid transparent;
  background: transparent;
  color: var(--text-faint);
  cursor: pointer;
  display: grid;
  place-items: center;
  transition: all 0.18s ease;

  &:hover {
    color: var(--accent);
    border-color: rgba(255, 255, 255, 0.2);
    background: rgba(255, 255, 255, 0.06);
  }
}

.preset-action-btn-old {
  display: none;
}

.preset-action-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 18px;
  border-radius: 12px;
  border: 1px solid var(--line);
  background: rgba(255, 255, 255, 0.05);
  color: var(--text-soft);
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.18s ease;

  &:hover {
    color: var(--text);
    border-color: rgba(255, 255, 255, 0.26);
  }
}

.opening-dialog-panel--wide {
  max-width: min(520px, var(--ui-max-width, 100%));
  max-height: min(80vh, calc(640px * var(--ui-scale, 1)));
  display: flex;
  flex-direction: column;
}

.opening-dialog-input {
  width: 100%;
  margin-bottom: var(--space-lg, 16px);
  padding: calc(12px * var(--ui-scale, 1)) calc(14px * var(--ui-scale, 1));
  border-radius: var(--radius-lg, 12px);
  border: 1px solid var(--line);
  background: rgba(255, 255, 255, 0.04);
  color: var(--text);
  font-size: calc(14px * var(--ui-scale, 1));

  &:focus {
    outline: none;
    border-color: rgba(255, 255, 255, 0.3);
  }
}

.opening-dialog-empty {
  margin: var(--space-sm, 8px) 0 var(--space-lg, 16px);
  padding: calc(20px * var(--ui-scale, 1));
  text-align: center;
  font-size: calc(14px * var(--ui-scale, 1));
  color: var(--text-faint);
  border-radius: calc(14px * var(--ui-scale, 1));
  border: 1px dashed var(--line);
}

.opening-dialog-list {
  list-style: none;
  margin: 0 0 var(--space-lg, 16px);
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: calc(10px * var(--ui-scale, 1));
}

.opening-dialog-list--scroll {
  overflow-y: auto;
  flex: 1;
  min-height: 0;
  max-height: calc(360px * var(--ui-scale, 1));
  padding-right: calc(4px * var(--ui-scale, 1));
}

.opening-dialog-list-item {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: calc(12px * var(--ui-scale, 1));
  padding: calc(12px * var(--ui-scale, 1)) calc(14px * var(--ui-scale, 1));
  border-radius: calc(14px * var(--ui-scale, 1));
  border: 1px solid var(--line);
  background: rgba(255, 255, 255, 0.04);
}

.opening-dialog-list-item--stack {
  flex-direction: column;
}

.opening-dialog-list-main {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.opening-dialog-list-name {
  font-size: calc(14px * var(--ui-scale, 1));
  font-weight: 600;
  color: var(--text);
}

.opening-dialog-list-meta {
  font-size: calc(12px * var(--ui-scale, 1));
  color: var(--text-faint);
}

.opening-dialog-list-preview {
  font-size: calc(12px * var(--ui-scale, 1));
  line-height: 1.45;
  color: var(--text-soft);
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.opening-dialog-list-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  flex-shrink: 0;
}

.opening-dialog-list-item--stack .opening-dialog-list-actions {
  align-self: flex-end;
}

.content-page {
  display: grid;
  grid-template-rows: auto 1fr;
}

.page-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 28px;
  border-bottom: 1px solid var(--line);
  background: rgba(255, 255, 255, 0.02);
}

.nav-btn {
  width: 42px;
  height: 42px;
  border-radius: 12px;
  border: 1px solid rgba(168, 85, 247, 0.4);
  background: rgba(168, 85, 247, 0.1);
  color: rgba(168, 85, 247, 0.9);
  cursor: pointer;
  transition: all 0.3s ease;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
  animation: nav-pulse 2s ease-in-out infinite;

  &::before {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, rgba(168, 85, 247, 0.2), rgba(6, 182, 212, 0.2));
    opacity: 0;
    transition: opacity 0.3s;
  }

  &:hover {
    color: #fff;
    border-color: rgba(6, 182, 212, 0.6);
    transform: translateY(-2px) scale(1.05);
    box-shadow:
      0 0 20px rgba(168, 85, 247, 0.4),
      0 0 40px rgba(6, 182, 212, 0.2);

    &::before {
      opacity: 1;
    }
  }

  &:active {
    transform: scale(0.96);
  }

  i {
    position: relative;
    z-index: 1;
    font-size: 16px;
  }
}

@keyframes nav-pulse {
  0%, 100% {
    box-shadow:
      0 0 5px rgba(168, 85, 247, 0.3),
      inset 0 0 10px rgba(168, 85, 247, 0.1);
  }
  50% {
    box-shadow:
      0 0 20px rgba(168, 85, 247, 0.5),
      0 0 30px rgba(6, 182, 212, 0.3),
      inset 0 0 15px rgba(168, 85, 247, 0.2);
  }
}

.placeholder {
  visibility: hidden;
}

.page-number {
  font-size: 12px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  font-weight: 600;
  background: linear-gradient(90deg, rgba(168, 85, 247, 0.8), rgba(6, 182, 212, 0.8));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow:
    0 0 20px rgba(168, 85, 247, 0.4),
    0 0 40px rgba(6, 182, 212, 0.2);
  position: relative;

  &::after {
    content: '';
    position: absolute;
    bottom: -4px;
    left: 50%;
    transform: translateX(-50%);
    width: 40px;
    height: 2px;
    background: linear-gradient(90deg, rgba(168, 85, 247, 0.6), rgba(6, 182, 212, 0.6));
    border-radius: 1px;
    box-shadow: 0 0 10px rgba(168, 85, 247, 0.5);
  }
}

.page-content {
  padding: 28px 30px 30px;
  overflow-y: auto;
  max-height: 610px;
}

.chapter-title {
  margin: 0 0 8px;
  font-size: 32px;
  font-weight: 700;
  letter-spacing: 0.05em;
  background: linear-gradient(135deg, #fff 0%, rgba(168, 85, 247, 0.9) 50%, rgba(6, 182, 212, 0.9) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow:
    0 0 30px rgba(168, 85, 247, 0.3),
    0 0 60px rgba(6, 182, 212, 0.2);
  position: relative;
  display: inline-block;

  &::after {
    content: '';
    position: absolute;
    bottom: -6px;
    left: 0;
    width: 60px;
    height: 3px;
    background: linear-gradient(90deg, rgba(168, 85, 247, 0.8), rgba(6, 182, 212, 0.8));
    border-radius: 2px;
    box-shadow: 0 0 15px rgba(168, 85, 247, 0.6);
  }
}

.chapter-desc {
  margin: 0 0 24px;
  color: var(--text-soft);
  font-size: 14px;
}

.scene-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
  margin-bottom: 24px;
}

.scene-card,
.rule-item,
.custom-rule-item,
.char-card,
.custom-rules-section,
.character-form,
.summary-section {
  border-radius: 18px;
  border: 1px solid var(--line);
  background: rgba(255, 255, 255, 0.04);
  transition: transform 0.2s cubic-bezier(0.22, 1, 0.36, 1), border-color 0.2s ease, box-shadow 0.2s ease;
}

.scene-card {
  padding: 16px;
  cursor: pointer;
  text-align: left;
  position: relative;
  overflow: hidden;
  border: 1px solid var(--line);
  border-radius: 16px;
  background: var(--glass);
  transition: all 0.3s ease;

  &:hover {
    transform: translateY(-2px);
    border-color: rgba(168, 85, 247, 0.4);
    box-shadow: 0 8px 22px rgba(0, 0, 0, 0.18);
  }

  &.active {
    transform: translateY(-2px);
    border-color: rgba(6, 182, 212, 0.6);
    box-shadow:
      0 8px 32px rgba(6, 182, 212, 0.2),
      0 0 20px rgba(168, 85, 247, 0.15),
      inset 0 0 20px rgba(6, 182, 212, 0.05);

    // 霓虹跑马灯光带
    &::before {
      content: '';
      position: absolute;
      top: 0;
      left: -100%;
      width: 100%;
      height: 2px;
      background: linear-gradient(
        90deg,
        transparent,
        rgba(168, 85, 247, 0.8),
        rgba(6, 182, 212, 0.8),
        rgba(168, 85, 247, 0.8),
        transparent
      );
      animation: neon-scan 3s linear infinite;
    }

    &::after {
      content: '';
      position: absolute;
      bottom: 0;
      right: -100%;
      width: 100%;
      height: 2px;
      background: linear-gradient(
        90deg,
        transparent,
        rgba(6, 182, 212, 0.8),
        rgba(168, 85, 247, 0.8),
        rgba(6, 182, 212, 0.8),
        transparent
      );
      animation: neon-scan-reverse 3s linear infinite;
    }

    .scene-icon {
      background: linear-gradient(135deg, rgba(168, 85, 247, 0.3), rgba(6, 182, 212, 0.3));
      box-shadow:
        0 0 15px rgba(168, 85, 247, 0.4),
        0 0 30px rgba(6, 182, 212, 0.2);
      animation: icon-pulse 2s ease-in-out infinite;
    }

    .scene-name {
      color: #fff;
      text-shadow: 0 0 10px rgba(6, 182, 212, 0.5);
    }
  }
}

@keyframes neon-scan {
  0% { left: -100%; }
  50% { left: 100%; }
  100% { left: 100%; }
}

@keyframes neon-scan-reverse {
  0% { right: -100%; }
  50% { right: 100%; }
  100% { right: 100%; }
}

@keyframes icon-pulse {
  0%, 100% {
    box-shadow:
      0 0 15px rgba(168, 85, 247, 0.4),
      0 0 30px rgba(6, 182, 212, 0.2);
  }
  50% {
    box-shadow:
      0 0 25px rgba(168, 85, 247, 0.6),
      0 0 50px rgba(6, 182, 212, 0.4);
  }
}

.scene-icon {
  width: 40px;
  height: 40px;
  border-radius: 12px;
  display: grid;
  place-items: center;
  margin-bottom: 10px;
  font-size: 20px;
  background: rgba(255, 255, 255, 0.1);
  color: var(--accent);
}

.scene-name {
  margin: 0 0 4px;
  font-size: 15px;
  font-weight: 600;
}

.scene-desc {
  margin: 0;
  font-size: 12px;
  line-height: 1.45;
  color: var(--text-soft);
}

.custom-scene {
  margin-top: 20px;
}

.custom-label {
  display: block;
  margin-bottom: 8px;
  font-size: 13px;
  font-weight: 600;
  color: var(--text-soft);
}

.custom-textarea,
.rule-name-input,
.rule-desc-input,
.char-name-input,
.char-gender-select,
.char-desc-input {
  width: 100%;
  padding: 12px 14px;
  border-radius: 14px;
