  font-size: 14px;
  transition: border-color 0.18s ease, box-shadow 0.18s ease, background 0.18s ease;

  &::placeholder {
    color: var(--text-faint);
  }

  &:focus {
    outline: none;
    border-color: rgba(255, 255, 255, 0.34);
