    background: rgba(255, 255, 255, 0.05);
  }
}

.custom-textarea,
.rule-desc-input,
.char-desc-input {
  resize: vertical;
  min-height: 86px;
}

.rules-section {
  margin-bottom: 22px;
}

.section-title {
  margin: 0 0 14px;
  font-size: 15px;
  font-weight: 700;
}

.rules-list {
  display: grid;
  gap: 10px;
}

.rule-item {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 14px;
  cursor: pointer;
  position: relative;
  overflow: hidden;
  border: 1px solid var(--line);
  border-radius: 14px;
  background: var(--glass);
  transition: all 0.3s ease;

  &:hover {
    border-color: rgba(168, 85, 247, 0.4);
    transform: translateY(-1px);
  }

  &.checked {
    border-color: rgba(6, 182, 212, 0.6);
    background: var(--glass-strong);
    transform: translateY(-1px);
    box-shadow:
      0 8px 32px rgba(6, 182, 212, 0.15),
      0 0 20px rgba(168, 85, 247, 0.1),
      inset 0 0 20px rgba(6, 182, 212, 0.05);

    // 霓虹跑马灯光带
    &::before {
      content: '';
      position: absolute;
      top: 0;
      left: -100%;
      width: 100%;
      height: 2px;
      background: linear-gradient(
        90deg,
        transparent,
        rgba(168, 85, 247, 0.8),
        rgba(6, 182, 212, 0.8),
        rgba(168, 85, 247, 0.8),
        transparent
      );
      animation: neon-scan 3s linear infinite;
    }

    &::after {
      content: '';
      position: absolute;
      bottom: 0;
      right: -100%;
      width: 100%;
      height: 2px;
      background: linear-gradient(
        90deg,
        transparent,
        rgba(6, 182, 212, 0.8),
        rgba(168, 85, 247, 0.8),
        rgba(6, 182, 212, 0.8),
        transparent
      );
      animation: neon-scan-reverse 3s linear infinite;
    }

    .check-mark {
      background: linear-gradient(135deg, rgba(168, 85, 247, 0.3), rgba(6, 182, 212, 0.3));
      border-color: rgba(6, 182, 212, 0.6);
      box-shadow:
        0 0 15px rgba(168, 85, 247, 0.4),
        inset 0 0 10px rgba(6, 182, 212, 0.2);
      animation: icon-pulse 2s ease-in-out infinite;

      i {
        color: #fff;
        text-shadow: 0 0 10px rgba(6, 182, 212, 0.8);
      }
    }

    .rule-name {
      color: #fff;
      text-shadow: 0 0 10px rgba(6, 182, 212, 0.3);
    }
  }
}

.rule-checkbox {
  position: relative;
  flex-shrink: 0;

  input {
    display: none;
  }
}

.check-mark {
  width: 22px;
  height: 22px;
  border-radius: 8px;
  border: 1px solid var(--line);
  background: rgba(255, 255, 255, 0.03);
  display: grid;
  place-items: center;
  color: var(--accent);
  transition: all 0.18s ease;

  i {
    font-size: 12px;
    opacity: 0;
    transform: scale(0.85);
    transition: all 0.18s ease;
  }

  input:checked + & {
    background: rgba(255, 255, 255, 0.16);
    border-color: rgba(255, 255, 255, 0.34);

    i {
      opacity: 1;
      transform: scale(1);
    }
  }
}

.rule-info,
.custom-rule-info,
.char-info {
  display: grid;
  gap: 4px;
  flex: 1;
  min-width: 0;
}

.rule-name,
.custom-rule-name,
.char-name {
  font-size: 14px;
  font-weight: 600;
}

.rule-desc,
.custom-rule-desc,
.char-desc {
  font-size: 12px;
  line-height: 1.45;
  color: var(--text-soft);
}

.custom-rules-section,
.character-form,
.summary-section {
  padding: 18px;
}

.custom-rule-input {
  display: grid;
  gap: 10px;
}

.form-row {
