    margin-bottom: 10px;
    font-size: 36px;
    color: var(--text-faint);
  }

  p {
    margin: 0 0 6px;
    font-size: 15px;
    font-weight: 600;
    color: var(--text-soft);
  }

  span {
    font-size: 12px;
    color: var(--text-faint);
  }
