.summary-label {
  font-size: 13px;
  color: var(--text-soft);
}

.summary-value {
  font-size: 13px;
  font-weight: 700;
}

.confirm-page {
  display: grid;
  grid-template-rows: auto 1fr;
  height: 100%;
}

.confirm-content {
  display: flex;
  flex-direction: column;
  min-height: 0;
  overflow-y: auto;
}

// 摘要在上，底部为「小预设按钮 + 开始游戏」成组贴底，避免预设条单独占一行挡住主按钮
.confirm-bottom {
  margin-top: auto;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 16px;
  width: 100%;
  padding-top: 8px;
}

.confirm-actions {
  display: grid;
  justify-items: center;
  width: 100%;
  padding: 0 0 12px;
}

// 炫酷开始游戏按钮
.cyber-start-btn {
  position: relative;
  min-width: 280px;
  padding: 18px 32px;
  font-size: 18px;
  font-weight: 700;
  border: none;
  border-radius: 16px;
  background: linear-gradient(135deg, rgba(168, 85, 247, 0.2), rgba(6, 182, 212, 0.2));
  color: #fff;
  cursor: pointer;
  overflow: hidden;
  transition: all 0.3s ease;
  animation: start-btn-pulse 2s ease-in-out infinite;

  .btn-glow {
    position: absolute;
    inset: -2px;
    border-radius: 18px;
    background: linear-gradient(135deg, #a855f7, #06b6d4, #a855f7);
    background-size: 200% 200%;
    z-index: -1;
    animation: gradient-rotate 3s ease infinite;
    filter: blur(8px);
    opacity: 0.6;
  }

  .btn-content {
    position: relative;
    z-index: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 12px;
    letter-spacing: 0.1em;

    i {
      font-size: 20px;
      transition: transform 0.3s;
    }
  }

  .btn-particles {
    position: absolute;
    inset: 0;
    pointer-events: none;
    overflow: hidden;

    .particle {
      position: absolute;
      width: 4px;
      height: 4px;
      background: rgba(6, 182, 212, 0.8);
      border-radius: 50%;
      animation: particle-float 2s ease-out infinite;

      &:nth-child(1) {
        left: 20%;
        bottom: -10px;
        animation-delay: 0s;
      }

      &:nth-child(2) {
        left: 50%;
        bottom: -10px;
        animation-delay: 0.5s;
      }

      &:nth-child(3) {
        left: 80%;
        bottom: -10px;
        animation-delay: 1s;
      }
    }
  }

  &:hover {
    transform: translateY(-3px) scale(1.02);
    box-shadow:
      0 20px 40px rgba(168, 85, 247, 0.3),
      0 0 60px rgba(6, 182, 212, 0.2);

    .btn-glow {
      opacity: 1;
      filter: blur(12px);
    }

    .btn-content i {
      transform: translateX(4px);
    }
  }

  &:active {
    transform: translateY(-1px) scale(0.98);
  }

  &:disabled {
    opacity: 0.45;
    cursor: not-allowed;
    animation: none;

    .btn-glow {
      animation: none;
      opacity: 0.2;
    }

    .btn-particles {
      display: none;
    }
  }
}

@keyframes start-btn-pulse {
  0%, 100% {
    box-shadow:
      0 0 20px rgba(168, 85, 247, 0.3),
      0 0 40px rgba(6, 182, 212, 0.2),
      inset 0 0 20px rgba(168, 85, 247, 0.1);
  }
  50% {
    box-shadow:
      0 0 30px rgba(168, 85, 247, 0.5),
      0 0 60px rgba(6, 182, 212, 0.3),
      inset 0 0 30px rgba(168, 85, 247, 0.2);
  }
}

@keyframes gradient-rotate {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

@keyframes particle-float {
  0% {
    transform: translateY(0) scale(1);
    opacity: 1;
  }
  100% {
    transform: translateY(-60px) scale(0);
    opacity: 0;
  }
}

// 开场预设：与文字行高接近的小按钮，横向并排，置于「开始游戏」正上方
.confirm-presets-bar {
  display: flex;
  flex-direction: row;
  flex-wrap: wrap;
  justify-content: center;
  align-items: center;
  gap: 8px 10px;
  width: 100%;
  padding: 0;
  border-top: none;
  background: transparent;
}

.cyber-preset-btn {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 5px 12px;
  min-height: 0;
  line-height: 1.35;
  border-radius: 999px;
  border: 1px solid rgba(168, 85, 247, 0.35);
  background: rgba(168, 85, 247, 0.08);
  color: rgba(255, 255, 255, 0.85);
  font-size: 12px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s ease;
  position: relative;
  overflow: hidden;
  flex: 0 1 auto;

  &::before {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, rgba(168, 85, 247, 0.2), rgba(6, 182, 212, 0.2));
    opacity: 0;
    transition: opacity 0.3s;
  }

  &:hover {
    color: #fff;
    border-color: rgba(6, 182, 212, 0.5);
    transform: translateY(-1px);
    box-shadow: 0 4px 12px rgba(168, 85, 247, 0.18);

    &::before {
      opacity: 1;
    }
  }

  i {
    position: relative;
    z-index: 1;
    font-size: 11px;
    color: rgba(168, 85, 247, 0.95);
  }

  span {
    position: relative;
    z-index: 1;
    white-space: nowrap;
  }
}

.hint-text {
  margin-top: 10px;
  color: var(--text-faint);
  font-size: 12px;
}

.chronicle-clear-btn {
  position: fixed;
  left: 20px;
  bottom: 20px;
  z-index: 50;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 0 14px;
  height: 44px;
  border-radius: 14px;
  border: 1px solid var(--line);
  background: var(--glass);
  color: var(--text-soft);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  backdrop-filter: blur(12px);
  transition: all 0.18s ease;

  i {
    font-size: 14px;
    opacity: 0.9;
  }

  &:hover {
    color: var(--text);
    border-color: rgba(255, 255, 255, 0.28);
    transform: translateY(-1px);
  }
}

.chronicle-dialog-backdrop {
  position: fixed;
  inset: 0;
  z-index: 200;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: calc(24px * var(--ui-scale, 1));
  background: rgba(0, 0, 0, 0.55);
  backdrop-filter: blur(6px);
}

.chronicle-dialog-panel {
  width: 100%;
  max-width: min(400px, var(--ui-max-width, 100%));
  padding: calc(22px * var(--ui-scale, 1)) calc(22px * var(--ui-scale, 1)) calc(18px * var(--ui-scale, 1));
  border-radius: calc(18px * var(--ui-scale, 1));
  border: 1px solid var(--line);
  background: var(--glass-strong);
  color: var(--text);
  box-shadow: 0 calc(24px * var(--ui-scale, 1)) calc(64px * var(--ui-scale, 1)) rgba(0, 0, 0, 0.35);
  backdrop-filter: blur(16px);
}

.chronicle-dialog-title {
  margin: 0 0 var(--space-md, 12px);
  font-size: calc(18px * var(--ui-scale, 1));
  font-weight: 600;
}

.chronicle-dialog-desc {
  margin: 0 0 calc(20px * var(--ui-scale, 1));
  font-size: calc(14px * var(--ui-scale, 1));
  line-height: 1.55;
  color: var(--text-soft);
}

.chronicle-dialog-actions {
  display: flex;
  justify-content: flex-end;
  gap: calc(10px * var(--ui-scale, 1));
}

.chronicle-dialog-btn {
  min-width: calc(88px * var(--ui-scale, 1));
  padding: calc(10px * var(--ui-scale, 1)) calc(16px * var(--ui-scale, 1));
  border-radius: var(--radius-lg, 12px);
  font-size: calc(14px * var(--ui-scale, 1));
  font-weight: 500;
  cursor: pointer;
  border: 1px solid var(--line);
  background: var(--glass);
  color: var(--text);
  transition: background 0.15s ease, border-color 0.15s ease;

  &.cancel:hover {
    border-color: rgba(255, 255, 255, 0.22);
  }

  &.danger {
    border-color: rgba(220, 60, 60, 0.45);
    background: rgba(220, 60, 60, 0.18);
    color: var(--danger);

    &:hover:not(:disabled) {
      background: rgba(220, 60, 60, 0.28);
    }
  }

  &:disabled {
    opacity: 0.55;
    cursor: not-allowed;
  }
}

.opening-form.light .chronicle-dialog-btn.danger {
  border-color: rgba(220, 60, 60, 0.35);
  background: rgba(220, 60, 60, 0.12);
}

.opening-settings-btn {
  position: fixed;
  right: 20px;
  bottom: 76px;
  z-index: 50;
  width: 44px;
  height: 44px;
  border-radius: 14px;
  border: 1px solid var(--line);
  background: var(--glass);
  color: var(--text-soft);
  cursor: pointer;
  backdrop-filter: blur(12px);
  transition: all 0.18s ease;
  display: grid;
  place-items: center;
  padding: 0;

  &:hover {
    color: var(--text);
    border-color: rgba(255, 255, 255, 0.28);
    transform: translateY(-1px);
  }

  i {
    font-size: 18px;
  }
}

.theme-toggle {
  position: fixed;
  right: 20px;
  bottom: 20px;
  z-index: 50;
  width: 44px;
  height: 44px;
  border-radius: 14px;
  border: 1px solid var(--line);
  background: var(--glass);
  color: var(--text-soft);
  cursor: pointer;
  backdrop-filter: blur(12px);
  transition: all 0.18s ease;

  &:hover {
    color: var(--text);
    border-color: rgba(255, 255, 255, 0.28);
    transform: translateY(-1px);
  }
}

.page-content {
  &::-webkit-scrollbar {
    width: 8px;
  }

  &::-webkit-scrollbar-thumb {
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.2);
  }
}

// ===== 响应式适配 =====

/* 大屏幕适配 (1400px 以下) */
@media (max-width: 1400px) {
  .book-container {
    max-width: 1200px;
    height: 88vh;
  }

  .cover-page {
    gap: 24px;
    padding: 40px 32px 32px;
  }

  .center-card-wrapper .center-card {
    width: min(100%, 340px);
    height: auto;
    min-height: 360px;

    .card-content {
      .book-icon {
        font-size: 56px;
      }

      .book-title {
        font-size: 36px;
      }
    }
  }
}

/* 中等屏幕适配 (1200px 以下) */
@media (max-width: 1200px) {
  .book-container {
    max-width: 1000px;
    height: 90vh;
    max-height: 800px;
  }

  .cover-page {
    grid-template-columns: 1fr 360px 1fr;
    gap: 20px;
    padding: 36px 28px 28px;
  }

  .center-card-wrapper .center-card {
    width: min(100%, 320px);
    height: auto;
    min-height: 340px;

    .card-content {
      .book-icon-wrapper {
        margin-bottom: 24px;
      }

      .book-icon {
        font-size: 52px;
      }

      .book-title {
        font-size: 32px;
      }

      .book-subtitle {
        font-size: 11px;
        margin-bottom: 24px;
      }

      .book-desc {
        font-size: 13px;
      }
    }
  }

  .center-card-wrapper .start-btn-wrapper {
    margin-top: 32px;

    .start-btn {
      padding: 14px 36px;
      font-size: 15px;
    }
  }

  .system-status-panel,
  .event-logs-panel {
    max-width: 280px;
  }
}

/* 平板和小屏幕适配 (1024px 以下) */
@media (max-width: 1024px) {
  .opening-form {
    padding: 20px;
  }

  .book-container {
    max-width: 100%;
    height: 92vh;
    max-height: none;
    border-radius: 24px;
  }

  // 封面页改为上下布局
  .cover-page {
    grid-template-columns: 1fr;
    grid-template-rows: auto 1fr auto;
    gap: 24px;
    padding: 32px 24px 24px;
    overflow-y: auto;

    // 隐藏左右面板在封面页
    .system-status-panel,
    .event-logs-panel {
      display: none;
    }
  }

  .center-card-wrapper {
    order: 1;
  }

  .center-card-wrapper .center-card {
    width: 100%;
    max-width: 400px;
    height: auto;
    min-height: 300px;
    padding: 40px 24px;

    .card-content {
      .book-icon-wrapper {
        margin-bottom: 20px;
      }

      .book-icon {
        font-size: 48px;
      }

      .book-title {
        font-size: 36px;
      }

      .book-subtitle {
        font-size: 12px;
        margin-bottom: 20px;
      }

      .book-desc {
        font-size: 14px;
      }
    }
  }

  .center-card-wrapper .start-btn-wrapper {
    order: 2;
    margin-top: 24px;

    .start-btn {
      padding: 16px 40px;
      font-size: 16px;
    }
  }

  .bottom-tools {
    order: 3;
    margin-top: 20px;
    flex-wrap: wrap;

    .tool-btn {
      padding: 10px 20px;
      font-size: 12px;
    }
  }

  // HUD 装饰简化
  .hud-decoration {
    .hud-side {
      display: none;
    }

    .data-bars {
      opacity: 0.15;
    }

    .ruler {
      opacity: 0.1;
    }
  }
}

/* 手机横屏和中等移动设备 (768px 以下) */
@media (max-width: 768px) {
  .opening-form {
    padding: 12px;
  }

  .book-container {
    height: 95vh;
    border-radius: 20px;
  }

  .cover-page {
    gap: 16px;
    padding: 24px 16px 16px;
  }

  .center-card-wrapper .center-card {
    min-height: 260px;
    padding: 32px 20px;
    border-radius: 20px;

    .card-content {
      .book-icon-wrapper {
        margin-bottom: 16px;
      }

      .book-icon {
        font-size: 42px;
      }

      .book-title {
        font-size: 30px;
      }

      .book-subtitle {
        font-size: 11px;
        letter-spacing: 0.2em;
        margin-bottom: 16px;
      }

      .book-desc {
        font-size: 13px;
      }
    }
  }

  .center-card-wrapper .start-btn-wrapper {
    margin-top: 20px;

    .start-btn {
      padding: 14px 32px;
      font-size: 15px;
    }
  }

  .bottom-tools {
    gap: 10px;

    .tool-btn {
      padding: 8px 16px;
      font-size: 12px;
      border-radius: 10px;
    }
  }

  // HUD 进一步简化
  .hud-decoration {
    .corner-mark {
      font-size: 8px;

      &.top-left,
      &.top-right,
      &.bottom-left,
      &.bottom-right {
        &::before {
          width: 20px;
          height: 20px;
        }
      }
    }

    .hud-top {
      gap: 10px;

      .hud-line {
        width: 60px;
      }

      .hud-label {
        font-size: 9px;
        letter-spacing: 0.2em;
      }
    }

    .hud-bottom {
      gap: 16px;

      .data-blocks {
        gap: 3px;

        .data-block {
          width: 6px;
        }
      }

      .hud-range {
        font-size: 9px;
      }
    }

    .data-bars {
      display: none;
    }
  }

  // 页面内容调整
  .page-content {
    padding: 20px 16px;
  }

  .chapter-title {
    font-size: 24px;

    &::after {
      width: 40px;
      height: 2px;
    }
  }

  .chapter-desc {
    font-size: 13px;
    margin-bottom: 16px;
  }

  // 确认页按钮调整
  .cyber-start-btn {
    min-width: 240px;
    padding: 16px 28px;
    font-size: 16px;
  }

  .confirm-bottom {
    gap: 14px;
  }

  .confirm-presets-bar {
    gap: 8px;
  }
}

/* 小屏手机 (480px 以下) */
@media (max-width: 480px) {
  .opening-form {
    padding: 8px;
    // 为右下角主题/设置与左下角清除编年史留出空间，避免与封面底栏重叠
    padding-bottom: calc(96px + env(safe-area-inset-bottom, 0px));
