    height: 96vh;
    border-radius: 16px;
    min-width: 0;
  }

  .cover-page {
    gap: 12px;
    padding: 20px 12px 12px;
  }

  .center-card-wrapper .center-card {
    min-height: 220px;
    padding: 24px 16px;
    border-radius: 16px;

    .card-content {
      .book-icon-wrapper {
        margin-bottom: 12px;

        .icon-glow {
          inset: -12px;
          filter: blur(12px);
        }
      }

      .book-icon {
        font-size: 36px;
      }

      .book-title {
        font-size: 26px;
      }

      .book-subtitle {
        font-size: 10px;
        letter-spacing: 0.15em;
        margin-bottom: 12px;
      }

      .book-desc {
        font-size: 12px;
        letter-spacing: 0.05em;
      }
    }

    .card-inner-border {
      inset: 12px;
      border-radius: 12px;

      &::before {
        inset: 12px;
        border-radius: 8px;
      }
    }
  }

  .center-card-wrapper .start-btn-wrapper {
    margin-top: 16px;

    .btn-pulse-ring {
      display: none;
    }

    .start-btn {
      padding: 12px 28px;
      font-size: 14px;
      border-radius: 40px;
    }
  }

  .bottom-tools {
    flex-direction: column;
    align-items: stretch;
    gap: 10px;

    .tool-btn {
      padding: 10px 14px;
      font-size: 11px;
      gap: 6px;
      flex: 0 0 auto;
      max-width: 100%;
      width: 100%;

      i {
        font-size: 12px;
      }
    }
  }

  // HUD 最小化
  .hud-decoration {
    .corner-mark {
      display: none;
    }

    .hud-top {
      top: 12px;

      .hud-line {
        width: 40px;
      }

      .hud-label {
        font-size: 8px;
        letter-spacing: 0.15em;
      }
    }

    .hud-bottom {
      bottom: 12px;

      .hud-range {
        font-size: 8px;
      }
    }
  }

  // 页面头部简化
  .page-header {
    padding: 16px 20px;

    .nav-btn {
      width: 36px;
      height: 36px;
      border-radius: 10px;

      i {
        font-size: 14px;
      }
    }

    .page-number {
      font-size: 11px;
    }
  }

  .page-content {
    padding: 16px 12px;
  }

  .chapter-title {
    font-size: 22px;
    margin-bottom: 6px;

    &::after {
      width: 32px;
      bottom: -4px;
    }
  }

  // 表单元素调整
  .scene-card {
    padding: 14px;

    .scene-icon {
      width: 36px;
      height: 36px;
      font-size: 18px;
      margin-bottom: 8px;
