    font-size: 9px;
  }

  .chapter-title {
    font-size: 18px;
  }

  .rule-item,
  .scene-card {
    padding: 10px;
  }
}

/* 高度限制适配 (短屏幕) */
@media (max-height: 700px) {
  .book-container {
    height: 94vh;
  }

  .cover-page {
    padding-top: 20px;
    padding-bottom: 16px;
  }

  .center-card-wrapper .center-card {
    min-height: auto;
    padding: 24px 20px;

    .card-content {
      .book-icon-wrapper {
        margin-bottom: 12px;
      }

      .book-title {
        font-size: 28px;
      }

      .book-subtitle {
        margin-bottom: 12px;
      }
    }
  }

  .center-card-wrapper .start-btn-wrapper {
    margin-top: 16px;
  }
}

/* 超短屏幕 (600px 以下高度) */
@media (max-height: 600px) {
  .opening-form {
    padding: 8px;
  }

  .book-container {
    height: 96vh;
  }

  // 封面页改为横向滚动或压缩
  .cover-page {
    grid-template-columns: 1fr;
    gap: 12px;
    padding: 16px;
    overflow-y: auto;
  }

  .center-card-wrapper .center-card {
    padding: 20px 16px;

    .card-content {
      .book-icon-wrapper {
        margin-bottom: 8px;
      }

      .book-icon {
        font-size: 32px;
      }

      .book-title {
        font-size: 24px;
      }

      .book-subtitle {
        margin-bottom: 8px;
      }

      .book-desc {
        font-size: 11px;
      }
    }
  }

  // 底部工具栏横向排列
  .bottom-tools {
    flex-direction: row;
    flex-wrap: wrap;
    justify-content: center;
    overflow-x: visible;
    gap: 8px;
    padding-bottom: 8px;

    .tool-btn {
      flex: 0 1 auto;
      flex-shrink: 0;
      padding: 6px 12px;
      font-size: 11px;
    }
  }

  // 隐藏部分HUD元素
  .hud-decoration {
    .hud-top,
    .hud-bottom {
      display: none;
    }
  }

  // 页面内容可滚动
  .page-content {
    max-height: calc(96vh - 60px);
    overflow-y: auto;
  }
}

/* 原有响应式规则整合 */
@media (max-width: 900px) {
  .opening-form {
    padding: 16px;
  }

  .book-container {
    min-height: 620px;
    border-radius: 22px;
  }

  .book-page {
    min-height: 620px;
  }

  .page-content {
    padding: 20px;
    max-height: 560px;
  }

  .chapter-title {
    font-size: 24px;
  }
}

@media (max-width: 640px) {
  .scene-grid {
    grid-template-columns: 1fr;
    gap: 12px;
  }

  .form-row {
    flex-direction: column;
    gap: 8px;
  }

  .char-gender-select {
    width: 100%;
  }

  .opening-settings-btn {
    right: 12px;
    bottom: 60px;
    width: 40px;
    height: 40px;
    border-radius: 12px;
  }

  .theme-toggle {
    right: 12px;
    bottom: 12px;
    width: 40px;
    height: 40px;
    border-radius: 12px;
  }

  .chronicle-clear-btn {
    left: 12px;
    bottom: 12px;
    padding: 0 12px;
    height: 40px;
    font-size: 12px;
    border-radius: 12px;
  }

  // 确认页调整
  .confirm-content {
    padding: 20px 16px;
  }

  .summary-section {
    margin: 12px 0 20px;
    padding: 14px;
  }

  .summary-item {
    padding: 8px 0;

    .summary-label,
    .summary-value {
      font-size: 12px;
    }
  }

  .confirm-actions {
    padding: 20px 0;
  }

  // 弹窗适配
  .chronicle-dialog-backdrop {
    padding: 12px 10px;
  }

  .chronicle-dialog-panel {
    padding: 18px;
    border-radius: 16px;
    max-height: min(88dvh, 800px);
    overflow-y: auto;
    -webkit-overflow-scrolling: touch;
    box-sizing: border-box;
  }

  .opening-dialog-panel--wide {
    max-width: min(calc(100vw - 20px), var(--ui-max-width, 100%));
  }

  .opening-dialog-list--scroll {
    max-height: min(48vh, calc(320px * var(--ui-scale, 1)));
  }

  .opening-dialog-list-item {
    padding: 10px 12px;
  }

  .chronicle-dialog-actions {
    gap: 8px;

    .chronicle-dialog-btn {
      min-width: 76px;
      padding: 8px 14px;
      font-size: 13px;
    }
  }
}

/* 窄手机：规则/角色表单与工具条纵向铺满，避免横向挤压 */
@media (max-width: 420px) {
  .library-toolbar {
    flex-direction: column;
    align-items: stretch;
  }

  .library-toolbar-btn {
    width: 100%;
    justify-content: center;
    box-sizing: border-box;
  }

  .add-rule-btn,
  .add-char-btn {
    width: 100%;
    justify-content: center;
    box-sizing: border-box;
  }

  .custom-rules-section,
  .character-form {
    padding: 12px 10px;
  }

  .custom-rule-input {
    gap: 8px;
  }

  .chronicle-dialog-backdrop {
    padding: 8px;
  }

  .chronicle-dialog-panel {
    padding: 14px 14px 12px;
  }

  .chronicle-dialog-title {
    font-size: 16px;
  }

  .chronicle-dialog-desc {
    font-size: 13px;
    margin-bottom: 14px;
  }

  .opening-dialog-list-item {
    flex-direction: column;
    align-items: stretch;
    gap: 10px;
  }

  .opening-dialog-list-item--stack .opening-dialog-list-actions {
    align-self: stretch;
    justify-content: flex-end;
  }
}
